        'module' => array(
            'somemodules' => 'Vì gói hiện tại chứa ít nhất một mô-đun nên bạn có thể <b>Triển khai</b> các mô-đun trong gói trong phiên bản SuiteCRM của bạn hoặc <b>Xuất bản</b> gói sẽ được cài đặt trong phiên bản SuiteCRM hiện tại hoặc một phiên bản khác bằng cách sử dụng <b>Trình tải mô-đun</b>.<br/><br/>Để cài đặt gói trực tiếp trong phiên bản SuiteCRM của bạn, hãy nhấp vào <b>Triển khai</b>.<br><br>Để tạo tệp .zip cho gói có thể tải và được cài đặt trong phiên bản SuiteCRM hiện tại và các phiên bản khác bằng <b>Trình tải mô-đun</b>, hãy nhấp vào <b>Xuất bản</b>.<br/><br/> Bạn có thể xây dựng mô-đun cho gói này theo từng giai đoạn và xuất bản hoặc triển khai khi bạn sẵn sàng làm như vậy. <br/><br/>Sau khi xuất bản hoặc triển khai một gói, bạn có thể thực hiện các thay đổi đối với thuộc tính gói và tùy chỉnh thêm các mô-đun. Sau đó xuất bản lại hoặc triển khai lại gói để áp dụng các thay đổi.',
            'editView' => 'Tại đây bạn có thể chỉnh sửa các trường hiện có. Bạn có thể xóa bất kỳ trường hiện có nào hoặc thêm các trường có sẵn ở bảng điều khiển bên trái.',
            'create' => 'Khi chọn loại <b>Loại</b> mô-đun mà bạn muốn tạo, hãy ghi nhớ các loại trường bạn muốn có trong mô-đun. <br/><br/>Mỗi mẫu mô-đun chứa một tập hợp các trường liên quan đến loại mô-đun được mô tả trong tiêu đề.<br/><br/><b>Cơ bản</b> - Cung cấp các trường cơ bản xuất hiện trong các mô-đun tiêu chuẩn, chẳng hạn như các trường Tên, Được chỉ định cho, Nhóm, Ngày tạo và Mô tả.<br/><br/> <b>Công ty</b> - Cung cấp các trường dành riêng cho tổ chức, chẳng hạn như Tên công ty, Ngành và Địa chỉ thanh toán. Sử dụng mẫu này để tạo các mô-đun tương tự như mô-đun Tài khoản tiêu chuẩn.<br/><br/> <b>Người</b> - Cung cấp các trường dành riêng cho từng cá nhân, chẳng hạn như Lời chào, Tiêu đề, Tên, Địa chỉ và Số điện thoại. Sử dụng mẫu này để tạo các mô-đun tương tự như mô-đun Người liên hệ và Khách hàng tiềm năng tiêu chuẩn.<br/><br/><b>Vấn đề</b> - Cung cấp các trường dành riêng cho trường hợp và lỗi, chẳng hạn như Số, Trạng thái, Mức độ ưu tiên và Mô tả. Sử dụng mẫu này để tạo các mô-đun tương tự như các mô-đun Trường hợp và Lỗi tiêu chuẩn.<br/><br/>Lưu ý: Sau khi tạo mô-đun, bạn có thể chỉnh sửa nhãn của các trường do mẫu cung cấp cũng như tạo các trường tùy chỉnh để thêm vào bố cục mô-đun.',
            'afterSave' => 'Tùy chỉnh mô-đun cho phù hợp với nhu cầu của bạn bằng cách chỉnh sửa và tạo các trường, thiết lập mối quan hệ với các mô-đun khác và sắp xếp các trường trong bố cục.<br/><br/>Để xem các trường mẫu và quản lý các trường tùy chỉnh trong mô-đun, hãy nhấp vào <b>Xem trường</b>.<br/><br/>Để tạo và quản lý mối quan hệ giữa mô-đun và các mô-đun khác, cho dù mô-đun đã có trong ứng dụng hay các mô-đun tùy chỉnh khác trong cùng một gói, hãy nhấp vào <b>Xem mối quan hệ</b>.<br/><br/>Để chỉnh sửa bố cục mô-đun, nhấp vào <b>Xem bố cục</b>. Bạn có thể thay đổi bố cục Chế độ xem chi tiết, Chế độ xem chỉnh sửa và Chế độ xem danh sách cho mô-đun giống như cách bạn làm đối với các mô-đun đã có trong ứng dụng trong Studio.<br/><br/> Để tạo một mô-đun có cùng thuộc tính với mô-đun hiện tại, hãy nhấp vào <b>Sao chép</b>. Bạn có thể tùy chỉnh thêm mô-đun mới.',
            'viewfields' => 'Các trường trong mô-đun có thể được tùy chỉnh cho phù hợp với nhu cầu của bạn.<br/><br/>Bạn không thể xóa các trường tiêu chuẩn nhưng có thể xóa chúng khỏi bố cục thích hợp trong trang Bố cục. <br/><br/>Bạn có thể nhanh chóng tạo các trường mới có thuộc tính tương tự với các trường hiện có bằng cách nhấp vào <b>Sao chép</b> trong biểu mẫu <b>Thuộc tính</b>. Nhập bất kỳ thuộc tính mới nào rồi nhấp vào <b>Lưu</b>.<br/><br/>Bạn nên đặt tất cả thuộc tính cho trường tiêu chuẩn và trường tùy chỉnh trước khi xuất bản và cài đặt gói chứa mô-đun tùy chỉnh.',
            'viewrelationships' => 'Bạn có thể tạo mối quan hệ nhiều-nhiều giữa mô-đun hiện tại và các mô-đun khác trong gói và/hoặc giữa mô-đun hiện tại và các mô-đun đã được cài đặt trong ứng dụng.<br><br> Để tạo mối quan hệ một-nhiều và một-một, hãy tạo các trường <b>Relate</b> và <b>Flex Relate</b> cho các mô-đun.',
            'viewlayouts' => 'Bạn có thể kiểm soát những trường nào có sẵn để thu thập dữ liệu trong <b>Chế độ xem chỉnh sửa</b>. Bạn cũng có thể kiểm soát dữ liệu nào sẽ hiển thị trong <b>Chế độ xem chi tiết</b>. Các quan điểm không nhất thiết phải trùng khớp. <br/><br/>Biểu mẫu Tạo nhanh được hiển thị khi nhấp vào <b>Tạo</b> trong bảng điều khiển con mô-đun. Theo mặc định, bố cục biểu mẫu <b>Tạo nhanh</b> giống với bố cục <b>Chế độ xem chỉnh sửa</b> mặc định. Bạn có thể tùy chỉnh biểu mẫu Tạo nhanh để nó chứa ít trường hơn và/hoặc khác với bố cục Chỉnh sửa dạng xem. <br><br>Bạn có thể xác định tính bảo mật của mô-đun bằng cách sử dụng tùy chỉnh Bố cục cùng với <b>Quản lý vai trò</b>.<br><br>',
            'existingModule' => 'Sau khi tạo và tùy chỉnh mô-đun này, bạn có thể tạo các mô-đun bổ sung hoặc quay lại gói để <b>Xuất bản</b> hoặc <b>Triển khai</b> gói.<br><br>Để tạo các mô-đun bổ sung, hãy nhấp vào <b>Sao chép</b> để tạo một mô-đun có cùng thuộc tính với mô-đun hiện tại hoặc điều hướng trở lại gói và nhấp vào <b>Mô-đun mới</b>.<br><br> Nếu bạn đã sẵn sàng <b>Xuất bản</b> hoặc <b>Triển khai</b> gói chứa mô-đun này, hãy điều hướng trở lại gói để thực hiện các chức năng này. Bạn có thể xuất bản và triển khai các gói chứa ít nhất một mô-đun.',
            'labels' => 'Nhãn của các trường tiêu chuẩn cũng như các trường tùy chỉnh có thể được thay đổi. Việc thay đổi nhãn trường sẽ không ảnh hưởng đến dữ liệu được lưu trữ trong các trường.',
        ),
